/**
 * AURA TRADING DESK — usePlatformFeatures Hook
 * Fetches tier limits from /api/billing/limits for frontend feature gating.
 * Exposes canUse(feature) and withinLimit(resource) helpers.
 */
import { useState, useEffect, useCallback, useMemo } from 'react';
import { getApiBase } from '../utils/platform';

function authHeaders() {
  try {
    const token = localStorage.getItem('aura_token');
    return token ? { Authorization: `Bearer ${token}` } : {};
  } catch { return {}; }
}

export default function usePlatformFeatures(pollInterval = 0) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchLimits = useCallback(() => {
    fetch(`${getApiBase()}/billing/limits`, { headers: authHeaders() })
      .then((r) => {
        if (!r.ok) throw new Error(`HTTP ${r.status}`);
        return r.json();
      })
      .then((d) => {
        setData(d);
        setLoading(false);
        setError(null);
      })
      .catch((err) => {
        setError(err.message);
        setLoading(false);
      });
  }, []);

  useEffect(() => {
    fetchLimits();
    if (pollInterval > 0) {
      const iv = setInterval(fetchLimits, pollInterval);
      return () => clearInterval(iv);
    }
  }, [fetchLimits, pollInterval]);

  /**
   * Check if user's tier includes a feature.
   * Examples: canUse('live_trading'), canUse('ml_analytics'), canUse('api_access')
   */
  const canUse = useCallback((feature) => {
    if (!data || !data.features) return false;

    // Direct boolean flags
    if (feature in data.features) return !!data.features[feature];

    // Check feature list
    return (data.features.feature_list || []).includes(feature);
  }, [data]);

  /**
   * Check if user is within a tier limit for a resource.
   * Examples: withinLimit('watchlists'), withinLimit('alerts'), withinLimit('bots')
   * Returns { allowed, current, max }
   */
  const withinLimit = useCallback((resource) => {
    if (!data || !data.limits || !data.limits[resource]) {
      return { allowed: true, current: 0, max: 999 };
    }
    const { current, max } = data.limits[resource];
    return { allowed: current < max, current, max };
  }, [data]);

  /**
   * Get the user's current tier key.
   */
  const tier = useMemo(() => data?.tier || 'free', [data]);
  const tierLabel = useMemo(() => data?.tier_label || 'Free', [data]);

  return {
    tier,
    tierLabel,
    limits: data?.limits || {},
    features: data?.features || {},
    canUse,
    withinLimit,
    loading,
    error,
    refetch: fetchLimits,
  };
}
